const LOG_BUFFER_MAX = 500;
const LOG_STORAGE_KEY = '@debug_logs';
const LOG_SESSION_KEY = '@debug_session';

class LogBuffer {
  constructor(maxSize = LOG_BUFFER_MAX) {
    this.maxSize = maxSize;
    this.buffer = [];
    this.sessionId = this._generateSessionId();
    this.flushTimer = null;
    this.flushInterval = 30000; // 30 seconds
  }

  _generateSessionId() {
    return `session_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
  }

  add(entry) {
    const logEntry = {
      ...entry,
      sessionId: this.sessionId,
      timestamp: new Date().toISOString(),
      id: `${Date.now()}_${Math.random().toString(36).substr(2, 6)}`,
    };

    this.buffer.push(logEntry);

    if (this.buffer.length > this.maxSize) {
      this.buffer = this.buffer.slice(-Math.floor(this.maxSize * 0.8));
    }

    this._scheduleFlush();
    return logEntry;
  }

  _scheduleFlush() {
    if (this.flushTimer) return;
    this.flushTimer = setTimeout(() => {
      this.flush();
      this.flushTimer = null;
    }, this.flushInterval);
  }

  async flush() {
    if (this.buffer.length === 0) return;
    try {
      const existing = await AsyncStorage.getItem(LOG_STORAGE_KEY);
      let logs = existing ? JSON.parse(existing) : [];
      logs = [...logs, ...this.buffer].slice(-this.maxSize);
      await AsyncStorage.setItem(LOG_STORAGE_KEY, JSON.stringify(logs));
      this.buffer = [];
    } catch (e) {
      // Silently fail - don't let logging break the app
    }
  }

  getBuffer() {
    return [...this.buffer];
  }

  clear() {
    this.buffer = [];
  }
}

